/**
 * A small floating AI assistant component that uses Gemini to answer basic academic queries.
 */
const AiAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [query, setQuery] = useState('');
  const [response, setResponse] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const askAi = async () => {
    if (!query.trim()) return;
    setIsLoading(true);
    setResponse('');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const res = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are a helpful university study assistant on a student portal. Answer this student's query briefly: ${query}`,
        config: {
            systemInstruction: "Keep answers academic, helpful, and concise (max 100 words).",
            temperature: 0.7
        }
      });
      setResponse(res.text || "I'm sorry, I couldn't process that.");
    } catch (error) {
      setResponse("The AI is taking a study break! Please try again later.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100]">
      {isOpen ? (
        <div className="w-80 glass-card rounded-3xl shadow-2xl p-6 border border-indigo-200 animate-slideUp">
          <div className="flex justify-between items-center mb-4">
            <h4 className="font-bold text-indigo-900 flex items-center">
              <i className="fas fa-robot mr-2"></i> Study Buddy
            </h4>
            <button onClick={() => setIsOpen(false)} className="text-slate-400 hover:text-slate-600">
              <i className="fas fa-times"></i>
            </button>
          </div>
          <p className="text-xs text-slate-500 mb-4">Ask anything about study techniques or topics!</p>
          <div className="space-y-4">
            <textarea 
              className="w-full h-24 p-3 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
              placeholder="e.g. How to prepare for DBMS finals?"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />
            <button 
              onClick={askAi}
              disabled={isLoading}
              className="w-full py-3 bg-indigo-600 text-white rounded-xl font-semibold hover:bg-indigo-700 disabled:bg-indigo-300 transition-colors shadow-lg"
            >
              {isLoading ? <i className="fas fa-spinner fa-spin"></i> : 'Ask Gemini'}
            </button>
            {response && (
              <div className="mt-4 p-4 bg-indigo-50 rounded-xl text-sm text-indigo-900 border border-indigo-100 max-h-40 overflow-y-auto">
                {response}
              </div>
            )}
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-14 h-14 bg-indigo-600 text-white rounded-full flex items-center justify-center shadow-2xl hover:bg-indigo-700 transform hover:scale-110 transition-all"
        >
          <i className="fas fa-robot text-2xl"></i>
        </button>
      )}
    </div>
  );
};

